//GeoPoint.js

/**
 *
 * @param {number} x
 * @param {number} y
 * @constructor
 */
export function GeoPoint(x, y) {
    this.x = x;
    this.y = y;
}

/**
 *
 * @return {{x: number, y: number}}
 */
GeoPoint.prototype.toJSON = function() {
    return {
        x: this.x,
        y: this.y
    };
};

/**
 *
 * @return {number[]}
 */
GeoPoint.prototype.toArray = function() {
    return [this.x, this.y];
};
